#include <iostream>
#include <fstream>
#include <string>
#include <unordered_set>

// Function to read words from a file and store them in an unordered set
void load_words(const std::string &filename, std::unordered_set<std::string> &words) {
    std::ifstream file(filename);
    if (!file.is_open()) {
        std::cerr << "Error opening file: " << filename << std::endl;
        exit(1);
    }

    std::string word;
    while (file >> word) {
        words.insert(word);
    }
}

int main() {
    // Load dictionary
    std::unordered_set<std::string> dictionary;
    load_words("dictionary.txt", dictionary);

    // Read text file
    std::ifstream text_file("text.txt");
    if (!text_file.is_open()) {
        std::cerr << "Error opening file: text.txt" << std::endl;
        return 1;
    }

    // Check spelling
    std::string word;
    bool first_misspelled_word = true;
    while (text_file >> word) {
        if (dictionary.find(word) == dictionary.end()) {
            if (first_misspelled_word) {
                std::cout << "Misspelled words:" << std::endl;
                first_misspelled_word = false;
            }
            std::cout << word << std::endl;
        }
    }

    if (first_misspelled_word) {
        std::cout << "No misspelled words found." << std::endl;
    }

    return 0;
}
